        let modified_window_sum: Int64 = 0
        for j in 0..k_half {
            modified_window_sum += 0 * prices[start + j]
        }
        for j in k_half..k {
            modified_window_sum += 1 * prices[start + j]
        }

        let current_profit = original_profit - window_sum + modified_window_sum
        if current_profit > max_profit {
            max_profit = current_profit
        }
    }

    return max_profit
}
