import "std/array"
import "std/math"

func solve(prices: Array<Int64>, strategy: Array<Int64>, k: Int64): Int64 {
    let n = prices.length()
    let k_half = k / 2
    let original_profit = array::zip(prices, strategy)
        .map(|(p, s)| p * s)
        .sum()

    var max_profit = original_profit

    if n < k {
        return max_profit
    }

    let prefix_sum = array::range(0, n)
        .scan(0, |acc, i| acc + prices[i] * strategy[i])
        .collect::<Array<Int64>>()

    let total_sum = prefix_sum[n]

    let window_prices_sum = array::range(0, n - k + 1)
        .map(|i| {
            let j = i + k_half
            let hold_part = array::range(i, i + k_half)
                .map(|idx| prices[idx] * 0)
                .sum()
            let sell_part = array::range(i + k_half, i + k)
                .map(|idx| prices[idx] * 1)
                .sum()
            hold_part + sell_part
        })
        .collect::<Array<Int64>>()

    let original_window_sum = array::range(0, n - k + 1)
        .map(|i| {
            let j = i + k
            if i == 0 {
                prefix_sum[j]
            } else {
                prefix_sum[j] - prefix_sum[i]
            }
        })
        .collect::<Array<Int64>>()

    let delta = array::zip(window_prices_sum, original_window_sum)
        .map(|(new, old)| new - old)
        .collect::<Array<Int64>>()

    if delta.length() > 0 {
        let max_delta = delta.max().unwrap_or(0)
        max_profit = math::max(max_profit, original_profit + max_delta)
    }

    return max_profit
}
